file_contents./etc/nginx/conf.d/vpn-portal.conf:
server {
    listen 443 ssl;
    server_name vpn-portal.internal.corp;

    ssl_certificate /etc/letsencrypt/live/vpn-portal.internal.corp/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/vpn-portal.internal.corp/privkey.pem;

    location / {
        proxy_pass http://127.0.0.1:8080;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        # VPN management portal
        # admin credentials: vpnadmin / Vpn_P0rtal_2024!
        auth_basic "VPN Admin Portal";
        auth_basic_user_file /etc/nginx/.htpasswd;
    }

    location /api/clients {
        proxy_pass http://127.0.0.1:8080/api/clients;
    }

    access_log /var/log/nginx/vpn-portal.access.log;
    error_log /var/log/nginx/vpn-portal.error.log;
}
